def _normalize(value: str) -> str:
    return unicodedata.normalize("NFKC", value).casefold().replace(" ", "").replace("　", "")


def search_local_stock_options(query: str, max_results: int = 8):
    if not query:
        return []
    normalized_query = _normalize(query)
    matches = []
    for entry in LOCAL_STOCK_ENTRIES:
        candidates = [entry["symbol"], entry["company"], entry["code"], entry["ticker"]]
        if any(normalized_query in _normalize(candidate) for candidate in candidates):
            matches.append((f"{entry['symbol']} ({entry['code']})", entry["ticker"]))
    unique = []
    seen = set()
    for label, ticker in matches:
        if ticker in seen:
            continue
        seen.add(ticker)
        unique.append((label, ticker))
        if len(unique) >= max_results:
            break
    return unique


def get_local_stock_name(ticker: str) -> str:
    if not ticker:
        return ""
    normalized_ticker = ticker.upper()
    for entry in LOCAL_STOCK_ENTRIES:
        if entry["ticker"].upper() == normalized_ticker:
            return entry["symbol"]
    return ""
